      }
    } else {
      turn_sign_ = memory_fresh ? -last_turn_memory_sign_ : +1;
      avoidance_phase_ = AvoidancePhase::Reverse;
      phase_start_time_ = now;
    }

    if (avoidance_phase_ == AvoidancePhase::None) {
      avoidance_phase_ = AvoidancePhase::Turn;
      phase_start_time_ = now;
