    publishCmd(-reverse_speed_, 0.0);
    if ((now - phase_start_time_).seconds() >= reverse_seconds_) {
      avoidance_phase_ = AvoidancePhase::Turn;
      phase_start_time_ = now;
    }
    return BT::NodeStatus::RUNNING;
