    const double scale = 1.0 - (yaw_abs - yaw_slow_rad_) / denom;
    lin *= clamp(scale, 0.0, 1.0);
  }

  lin = std::max(lin, min_lin_);
  publishCmd(lin, ang);
  return BT::NodeStatus::RUNNING;
}

